import React, { useState, useEffect } from 'react';
import './App.css';

const gridSize = 8;

const baseCharacters = [
  { name: 'Knight', hp: 100, atk: 30, sprite: '/sprites/knight.png' },
  { name: 'Archer', hp: 80, atk: 25, sprite: '/sprites/archer.png' },
  { name: 'Mage', hp: 70, atk: 40, sprite: '/sprites/mage.png' },
  { name: 'Healer', hp: 90, atk: 10, sprite: '/sprites/healer.png' },
  { name: 'Warrior', hp: 110, atk: 35, sprite: '/sprites/warrior.png' },
  { name: 'Rogue', hp: 75, atk: 30, sprite: '/sprites/rogue.png' },
  { name: 'Summoner', hp: 65, atk: 45, sprite: '/sprites/summoner.png' },
  { name: 'Paladin', hp: 95, atk: 20, sprite: '/sprites/paladin.png' },
];

let idCounter = 1;
const generateTeam = (team, row) => baseCharacters.map((c, i) => ({
  ...c,
  id: idCounter++,
  x: i,
  y: row,
  team,
  hasMoved: false,
  hasAttacked: false,
}));

const initialCharacters = [
  ...generateTeam('A', 0),
  ...generateTeam('B', gridSize - 1)
];

function App() {
  const [characters, setCharacters] = useState(initialCharacters);
  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');
  const [actionMode, setActionMode] = useState(null); // 'move' or 'attack' or null
  const [attackTargets, setAttackTargets] = useState([]);

  const selectedChar = characters.find(c => c.id === selectedId);

  // Highlight tiles for movement (adjacent empty tiles) and attacks (adjacent enemy tiles)
  const getAdjacentTiles = (char) => {
    if (!char) return [];
    const directions = [
      [1, 0], [-1, 0], [0, 1], [0, -1]
    ];
    return directions.map(([dx, dy]) => ({ x: char.x + dx, y: char.y + dy }))
      .filter(({ x, y }) => x >= 0 && x < gridSize && y >= 0 && y < gridSize);
  };

  const moveTiles = selectedChar && !selectedChar.hasMoved && actionMode === 'move'
    ? getAdjacentTiles(selectedChar).filter(pos =>
      !characters.some(c => c.x === pos.x && c.y === pos.y)
    ) : [];

  const attackTiles = selectedChar && !selectedChar.hasAttacked && actionMode === 'attack'
    ? getAdjacentTiles(selectedChar).filter(pos =>
      characters.some(c => c.x === pos.x && c.y === pos.y && c.team !== selectedChar.team)
    ) : [];

  // When user clicks on a tile during move mode
  const handleMoveClick = (x, y) => {
    if (!selectedChar || selectedChar.hasMoved) return;

    const canMoveHere = moveTiles.some(pos => pos.x === x && pos.y === y);
    if (!canMoveHere) return;

    setCharacters(prev =>
      prev.map(c => c.id === selectedChar.id ? { ...c, x, y, hasMoved: true } : c)
    );

    setActionMode(null);
  };

  // When user clicks on a tile during attack mode
  const handleAttackClick = (x, y) => {
    if (!selectedChar || selectedChar.hasAttacked) return;

    const target = characters.find(c => c.x === x && c.y === y && c.team !== selectedChar.team);
    if (!target) return;

    setCharacters(prev =>
      prev
        .map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - selectedChar.atk) } : c
        )
        .filter(c => c.hp > 0) // Remove dead
        .map(c => c.id === selectedChar.id ? { ...c, hasAttacked: true } : c)
    );

    setActionMode(null);
  };

  // Reset all characters' move and attack flags at turn end
  const endTurn = () => {
    setCharacters(prev =>
      prev.map(c => {
        if (c.team === turn) return { ...c, hasMoved: false, hasAttacked: false };
        return c;
      })
    );
    setSelectedId(null);
    setActionMode(null);
    setTurn(prev => (prev === 'A' ? 'B' : 'A'));
  };

  // On tile click handler: select character or move/attack tile
  const handleTileClick = (x, y) => {
    if (actionMode === 'move') {
      handleMoveClick(x, y);
      return;
    }
    if (actionMode === 'attack') {
      handleAttackClick(x, y);
      return;
    }

    // If clicking on a character from current team, select/deselect
    const char = characters.find(c => c.x === x && c.y === y);
    if (char && char.team === turn) {
      setSelectedId(char.id === selectedId ? null : char.id);
      setActionMode(null);
    } else {
      // Clicked empty tile or enemy tile outside action mode — deselect
      setSelectedId(null);
      setActionMode(null);
    }
  };

  return (
    <div className="App">
      <h1>DuelGrid</h1>
      <h2>Turn: Team {turn}</h2>
      <div className="grid">
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row">
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find(c => c.x === x && c.y === y);
              const isSelected = char && char.id === selectedId;
              const isMoveHighlight = moveTiles.some(pos => pos.x === x && pos.y === y);
              const isAttackHighlight = attackTiles.some(pos => pos.x === x && pos.y === y);

              return (
                <div
                  key={x}
                  className={`tile
                    ${char ? 'occupied' : ''}
                    ${isSelected ? 'selected' : ''}
                    ${isMoveHighlight ? 'move-highlight' : ''}
                    ${isAttackHighlight ? 'attack-highlight' : ''}
                  `}
                  onClick={() => handleTileClick(x, y)}
                >
                  {char && (
                    <div className="character">
                      <img src={char.sprite} alt={char.name} className="sprite" />
                      <div className="stats">
                        <div>{char.name}</div>
                        <HPBar hp={char.hp} maxHp={baseCharacters.find(bc => bc.name === char.name)?.hp || 100} />
                        <div>ATK: {char.atk}</div>
                        {char.hasMoved && <div className="action-flag">Moved</div>}
                        {char.hasAttacked && <div className="action-flag">Attacked</div>}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>

      <div className="controls">
        {selectedChar && selectedChar.team === turn && (
          <>
            {!selectedChar.hasMoved && (
              <button onClick={() => setActionMode('move')}>
                Move
              </button>
            )}
            {!selectedChar.hasAttacked && (
              <button onClick={() => setActionMode('attack')}>
                Attack
              </button>
            )}
            <button onClick={() => { setSelectedId(null); setActionMode(null); }}>
              Deselect
            </button>
          </>
        )}
        <button onClick={endTurn}>End Turn</button>
      </div>
    </div>
  );
}

// Simple health bar component
const HPBar = ({ hp, maxHp }) => {
  const percentage = Math.max(0, Math.min(100, (hp / maxHp) * 100));
  return (
    <div className="hp-bar">
      <div
        className="hp-fill"
        style={{ width: `${percentage}%`, backgroundColor: percentage > 50 ? 'limegreen' : percentage > 20 ? 'orange' : 'red' }}
      />
      <span className="hp-text">{hp} / {maxHp}</span>
    </div>
  );
};

export default App;
